UPDATE pr
SET base_sha  = #{baseSha},
    head_sha  = #{headSha},
    start_sha = #{startSha},
    is_opened = #{isOpened}
WHERE repo_id = #{repoId}
  AND pr_id = #{prId}

UPDATE pr_temp
SET temp_status = 1
WHERE
    repo_id = #{repoId}
  AND
    pr_id = #{prId}

mapper.select:
SELECT EXISTS (
    SELECT 1 FROM pr
    WHERE repo_id = #{repoId} AND pr_id = #{prId}
) AS result;

